public static long fact(int k) {
    if (k <= 1) {
        return 1;
    }
    return k * fact(k - 1);
}

public int vowelCount(String input) {
    int hits = 0;
    for (char ch : input.toLowerCase().toCharArray()) {
        if ("aeiou".indexOf(ch) >= 0) {
            hits++;
        }
    }
    return hits;
}

public static double discounted(double cost, double percent) {
    return cost - (cost * percent / 100);
}

public static String upperFirst(String word) {
    if (word == null || word.length() == 0) {
        return word;
    }
    return word.substring(0, 1).toUpperCase() + word.substring(1);
}

public static double mean(List<Integer> values) {
    int sum = 0;
    for (Integer v : values) {
        sum += v;
    }
    return (double) sum / values.size();
}

public static boolean checkEmail(String addr) {
    if (addr == null) {
        return false;
    }
    int atPos = addr.indexOf('@');
    int dotPos = addr.lastIndexOf('.');
    return atPos > 0 && dotPos > atPos + 1 && dotPos < addr.length() - 1;
}

public static void bubbleSort(int[] arr) {
    for (int i = 0; i < arr.length - 1; i++) {
        for (int j = 0; j < arr.length - 1 - i; j++) {
            if (arr[j] > arr[j + 1]) {
                int tmp = arr[j];
                arr[j] = arr[j + 1];
                arr[j + 1] = tmp;
            }
        }
    }
}

public static long fibonacci(int n) {
    long a = 0;
    long b = 1;
    for (int i = 0; i < n; i++) {
        long next = a + b;
        a = b;
        b = next;
    }
    return a;
}

public static double toFahrenheit(double celsius) {
    double scaled = celsius * 9 / 5;
    double result = scaled + 32;
    return result;
}

public static double standardDeviation(double[] data) {
    double sum = 0;
    for (double d : data) {
        sum += d;
    }
    double avg = sum / data.length;
    double sq = 0;
    for (double d : data) {
        sq += (d - avg) * (d - avg);
    }
    return Math.sqrt(sq / data.length);
}
